import { Component, OnInit } from '@angular/core';
import { PopoverController } from '@ionic/angular';
import { UserService } from '../services/user.service';
import { RightMenuComponent } from './../components/right-menu/right-menu.component';

@Component({
  selector: 'app-orders',
  templateUrl: './orders.page.html',
  styleUrls: ['./orders.page.scss'],
})
export class OrdersPage implements OnInit {

  is_load: boolean = false;
  is_reload: boolean = false;
  orders:any = [];

  constructor(private userService:UserService,public popoverController: PopoverController) { }

  ngOnInit() {
    this.loadLeads();
  }

  loadLeads() {
    this.orders = []
    this.userService.loadLeads().then(response =>{
      console.log("this.userService.loadLeads:");
      console.log(response);
      response.deals.forEach(lead => {
        this.orders.push(lead);
      });
      this.is_load = true;
    })
  }

  async openRightMenu(e: Event) {
    const popover = await this.popoverController.create({
      component: RightMenuComponent,
      event: e
    });

    await popover.present();
 
  }

  doRefresh(event) {
    console.log('Begin async operation');
    this.is_reload = true;

    this.userService.loadLeads().then(response =>{
      console.log("this.userService.loadLeads:");
      console.log(response);
      this.orders = [];
      response.deals.forEach(lead => {
        this.orders.push(lead);
        event.target.complete();
      });
      this.is_reload = false;
    });
  }


}
