import { Component, OnInit } from '@angular/core';
import { IonInput, ModalController, NavController, PopoverController, ToastController } from '@ionic/angular';
import { NgxMaskModule,MaskPipe } from 'ngx-mask';
import {UserService} from '../../services/user.service';

@Component({
  selector: 'app-right-menu',
  templateUrl: './right-menu.component.html',
  styleUrls: ['./right-menu.component.scss'],
})
export class RightMenuComponent implements OnInit {

  constructor(private userService:UserService, private nav:NavController,public popoverController: PopoverController) { }

  ngOnInit() {}


  logout() {
    this.userService.logout().then( ()=>{
      this.popoverController.dismiss();
      this.nav.navigateRoot(['start'],{animationDirection:"back"});
    })
  }
}
